// Webhook с multipart складывает все файлы в одно item.binary с ключами
// data, data_0, data_1, ... Для последующего Spreadsheet File нужно, чтобы
// каждый файл был отдельным item с одним фиксированным binary-ключом «data».
//
// Binary получаем через helpers.getBinaryDataBuffer/prepareBinaryData, а не
// копированием meta-объекта — иначе в filesystem-mode n8n ссылка на исходный
// файл может потеряться.
//
// При любой ошибке валидации возвращаем один item с success:false, чтобы
// IF-нода ниже перенаправила в JSON-ответ с кодом 400.

const input = $input.first();
const binary = input.binary || {};
const keys = Object.keys(binary);

if (keys.length === 0) {
  return [{ json: { success: false, error: 'Не загружено ни одного файла.' } }];
}

const items = [];
let fileIndex = 0;
for (const key of keys) {
  const meta = binary[key] || {};
  const fileName = meta.fileName || ('file-' + fileIndex + '.xlsx');
  const lower = fileName.toLowerCase();
  if (!(lower.endsWith('.xlsx') || lower.endsWith('.xlsm'))) {
    return [{ json: { success: false, error: 'Файл «' + fileName + '» имеет неподдерживаемое расширение. Принимаются только .xlsx и .xlsm.' } }];
  }

  // Читаем буфер явно и пересоздаём binary entry — это надёжнее, чем передавать meta
  let buf;
  try {
    buf = await this.helpers.getBinaryDataBuffer(0, key);
  } catch (e) {
    return [{ json: { success: false, error: 'Не удалось прочитать файл «' + fileName + '»: ' + (e.message || e) } }];
  }
  const binaryData = await this.helpers.prepareBinaryData(
    Buffer.from(buf),
    fileName,
    meta.mimeType || 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
  );

  items.push({
    json: { fileIndex: fileIndex, fileName: fileName, success: true },
    binary: { data: binaryData }
  });
  fileIndex++;
}

return items;

// Прикрепляем к каждой строке индекс исходного файла через явный
// $('Разбить на items').item — n8n сам резолвит соответствие через
// pairedItem, нам не нужно полагаться на это вручную.
// Этот узел работает в режиме «runOnceForEachItem», что и активирует
// корректную работу $('node').item для текущего item.

const fileIndex = $('Разбить на items').item.json.fileIndex;
const fileName = $('Разбить на items').item.json.fileName;
return {
  json: Object.assign({}, $json, { _fileIndex: fileIndex, _fileName: fileName })
};

// На входе — items от «Маркировать fileIndex». Каждый item — одна строка xlsx,
// json содержит поля по заголовкам файла плюс _fileIndex / _fileName.
//
// Логика слияния:
//   1) Нормализуем заголовки (без пробелов, точек, регистра).
//   2) Объединяем порядок столбцов: первые столбцы первого файла → лишние
//      из второго → и т.д. (стабильно для пользователя).
//   3) Отображаемое имя столбца — первое встреченное.
//   4) Для каждой строки строим новую строку в едином порядке столбцов.
//      Если в исходной таблице столбца не было — пусто.
//
// При ошибке возвращаем один item с success:false для роутинга через IF.

function normalize(h) {
  if (h == null) return '';
  return String(h).trim().toLowerCase().replace(/[\s._\-(){}\[\]\\/:;,!?'\"]+/g, '');
}

try {
  const items = $input.all();
  if (items.length === 0) {
    return [{ json: { success: false, error: 'После чтения файлов не осталось ни одной строки данных.' } }];
  }

  // Группируем строки по индексу исходного файла (по полю _fileIndex,
  // которое прикрепил «Маркировать fileIndex»).
  const byFile = new Map();
  for (const item of items) {
    const j = item.json || {};
    const idx = (typeof j._fileIndex === 'number') ? j._fileIndex : 0;
    if (!byFile.has(idx)) byFile.set(idx, []);
    // Чистим служебные поля из json — они не должны попасть в итог
    const clean = Object.assign({}, j);
    delete clean._fileIndex;
    delete clean._fileName;
    byFile.get(idx).push(clean);
  }

  // Порядок столбцов в итоге + каноническое отображаемое имя
  const columnOrder = [];
  const canonical = {};
  for (const rows of byFile.values()) {
    if (rows.length === 0) continue;
    for (const k of Object.keys(rows[0])) {
      const norm = normalize(k);
      if (!norm) continue;
      if (!(norm in canonical)) {
        canonical[norm] = k;
        columnOrder.push(norm);
      }
    }
  }

  if (columnOrder.length === 0) {
    return [{ json: { success: false, error: 'Во всех файлах заголовки пустые — нечего объединять.' } }];
  }

  // Собираем итоговые строки
  const mergedRows = [];
  for (const rows of byFile.values()) {
    if (rows.length === 0) continue;
    const localMap = {};
    for (const k of Object.keys(rows[0])) {
      const norm = normalize(k);
      if (norm && !(norm in localMap)) localMap[norm] = k;
    }
    for (const row of rows) {
      const newRow = {};
      for (const norm of columnOrder) {
        const displayName = canonical[norm];
        const srcKey = localMap[norm];
        const v = srcKey != null ? row[srcKey] : null;
        newRow[displayName] = v == null ? '' : v;
      }
      mergedRows.push(newRow);
    }
  }

  if (mergedRows.length === 0) {
    return [{ json: { success: false, error: 'Во всех файлах нет данных кроме заголовков.' } }];
  }

  return mergedRows.map(r => ({ json: r }));
} catch (e) {
  return [{ json: { success: false, error: 'Ошибка слияния: ' + (e.message || e) } }];
}
